import argparse
import json
import os
import random
import numpy as np
import heapq
from collections import deque
from cogniplan_env import ExplorationEnv


def dijkstra(adj, start):
    N = len(adj)
    dist = [float('inf')] * N
    prev = [None] * N
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u] + 1e-9:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd + 1e-9 < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def round_coord(c):
    return tuple(np.round(np.array(c, dtype=float), 6))


def build_graph(nodes, robot_pos, cur_neighbors):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord_to_idx[round_coord(n["coords"])] = i
    N = len(nodes)
    adj = [[] for _ in range(N)]
    for i, n in enumerate(nodes):
        for nb in n.get("neighbors", []):
            j = None
            if isinstance(nb, dict):
                nb = nb.get("coords", nb)
            if isinstance(nb, (list, tuple, np.ndarray)):
                j = coord_to_idx.get(round_coord(nb))
            else:
                try:
                    j = int(nb)
                    if not (0 <= j < N):
                        j = None
                except (ValueError, TypeError):
                    j = None
            if j is not None and j != i:
                w = float(np.linalg.norm(
                    np.array(n["coords"], dtype=float) -
                    np.array(nodes[j]["coords"], dtype=float)
                ))
                adj[i].append((j, w))
    r_idx = N
    adj.append([])
    for nb in cur_neighbors:
        j = coord_to_idx.get(round_coord(nb))
        if j is None:
            continue
        w = float(np.linalg.norm(
            np.array(robot_pos, dtype=float) -
            np.array(nb, dtype=float)
        ))
        adj[r_idx].append((j, w))
        adj[j].append((r_idx, w))
    return adj, coord_to_idx, r_idx


class SimpleGreedyPlanner:
    def __init__(self, dist_denom=1.0, visited_penalty=0.1, history_penalty=0.5, history_len=12):
        self.dist_denom = dist_denom
        self.visited_penalty = visited_penalty
        self.history_penalty = history_penalty
        self.history_len = history_len
        self.reset()

    def reset(self):
        self.step_count = 0
        self.history = deque(maxlen=self.history_len)
        self.prev_pos = None

    def plan(self, obs):
        self.step_count += 1
        robot_pos = np.array(obs["robot_pos"], dtype=float)
        neighbors = obs["neighbors"]
        nodes = obs["nodes"]
        frontiers = obs.get("frontiers", [])

        if not neighbors:
            return None

        adj, coord_to_idx, r_idx = build_graph(nodes, robot_pos, neighbors)
        dist, prev = dijkstra(adj, r_idx)
        N = len(nodes)

        nb_to_node = {}
        node_to_nb = {}
        for idx, nb in enumerate(neighbors):
            j = coord_to_idx.get(round_coord(nb))
            if j is not None:
                nb_to_node[idx] = j
                node_to_nb[j] = idx

        first_step = {}
        for j in range(N):
            if dist[j] == float('inf') or prev[j] is None:
                continue
            cur = j
            depth = 0
            while prev[cur] != r_idx and prev[cur] is not None and depth < N + 5:
                cur = prev[cur]
                depth += 1
            if prev[cur] == r_idx and cur in node_to_nb:
                first_step[j] = node_to_nb[cur]

        remaining_steps = 128 - self.step_count
        best_score = -float('inf')
        best_node = None

        # Primary: nodes with positive utility
        for j in range(N):
            if j not in first_step:
                continue
            utility = float(nodes[j].get("utility", 0.0))
            if utility <= 0:
                continue
            d = dist[j]
            score = utility / (d + self.dist_denom)
            if nodes[j].get("visited", False):
                score *= self.visited_penalty
            if j in self.history:
                score *= self.history_penalty
            est_steps = max(d / 3.2, 1.0)
            if est_steps > remaining_steps:
                continue
            if score > best_score:
                best_score = score
                best_node = j

        # Fallback 1: nearest unvisited node
        if best_node is None:
            for j in range(N):
                if j not in first_step:
                    continue
                if nodes[j].get("visited", False):
                    continue
                d = dist[j]
                score = 1.0 / (d + self.dist_denom)
                if j in self.history:
                    score *= self.history_penalty
                if score > best_score:
                    best_score = score
                    best_node = j

        # Fallback 2: nearest node to any frontier
        if best_node is None and frontiers:
            frontier_arr = np.array(frontiers, dtype=float)
            for j in range(N):
                if j not in first_step:
                    continue
                node_pos = np.array(nodes[j]["coords"], dtype=float)
                df = np.linalg.norm(frontier_arr - node_pos, axis=1)
                min_df = float(np.min(df))
                d = dist[j]
                score = 1.0 / (d + min_df + self.dist_denom)
                if j in self.history:
                    score *= self.history_penalty
                if score > best_score:
                    best_score = score
                    best_node = j

        # Fallback 3: any neighbor, prefer unvisited, avoid reversing
        if best_node is None:
            candidates = []
            for idx, nb in enumerate(neighbors):
                j = nb_to_node.get(idx)
                is_visited = False
                if j is not None:
                    is_visited = nodes[j].get("visited", False)
                backtrack = False
                if self.prev_pos is not None:
                    if np.linalg.norm(np.array(nb) - np.array(self.prev_pos)) < 0.5:
                        backtrack = True
                candidates.append((idx, is_visited, backtrack))
            # Prefer unvisited non-backtrack
            preferred = [idx for idx, vis, bt in candidates if not vis and not bt]
            if not preferred:
                preferred = [idx for idx, vis, bt in candidates if not bt]
            if not preferred:
                preferred = [idx for idx, _, _ in candidates]
            chosen = random.choice(preferred) if preferred else 0
            self.prev_pos = robot_pos.copy()
            return neighbors[chosen]

        self.history.append(best_node)
        chosen_nb_idx = first_step[best_node]
        chosen_nb = neighbors[chosen_nb_idx]

        # Anti-backtracking: if the chosen step reverses previous move, try second best
        if self.prev_pos is not None and len(neighbors) > 1:
            if np.linalg.norm(np.array(chosen_nb) - np.array(self.prev_pos)) < 0.5:
                second_best_score = -float('inf')
                second_best_node = None
                for j in range(N):
                    if j not in first_step or j == best_node:
                        continue
                    utility = float(nodes[j].get("utility", 0.0))
                    if utility <= 0:
                        continue
                    d = dist[j]
                    score = utility / (d + self.dist_denom)
                    if nodes[j].get("visited", False):
                        score *= self.visited_penalty
                    if j in self.history:
                        score *= self.history_penalty
                    est_steps = max(d / 3.2, 1.0)
                    if est_steps > remaining_steps:
                        continue
                    nb_idx = first_step[j]
                    nb = neighbors[nb_idx]
                    if np.linalg.norm(np.array(nb) - np.array(self.prev_pos)) < 0.5:
                        continue
                    if score > second_best_score:
                        second_best_score = score
                        second_best_node = j
                if second_best_node is not None:
                    best_node = second_best_node
                    chosen_nb_idx = first_step[best_node]
                    chosen_nb = neighbors[chosen_nb_idx]

        self.prev_pos = robot_pos.copy()
        return chosen_nb


def run_episode(env, planner):
    obs = env.reset()
    planner.reset()
    done = False
    for _ in range(128):
        if done:
            break
        target = planner.plan(obs)
        if target is None:
            break
        obs, info = env.step(target)
        done = info.get("done", False)
    return env.get_metrics()


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", required=True)
    parser.add_argument("--checkpoint", required=True)
    parser.add_argument("--output", required=True)
    args = parser.parse_args()

    ckpt_path = os.path.join(args.checkpoint, "policy.pt")
    if os.path.exists(ckpt_path):
        import torch
        _ = torch.load(ckpt_path, map_location="cpu")

    data_path = args.data_path
    eval_config_path = os.path.join(data_path, "eval_config.json")

    episodes = []
    if os.path.exists(eval_config_path):
        with open(eval_config_path, "r") as f:
            config = json.load(f)
        if isinstance(config, list):
            episodes = config
        elif isinstance(config, dict):
            if "episodes" in config:
                episodes = config["episodes"]
            elif "maps" in config:
                episodes = config["maps"]

    if not episodes:
        maps_dir = os.path.join(data_path, "maps_eval")
        for env_type in ["room", "tunnel", "outdoor"]:
            type_dir = os.path.join(maps_dir, env_type)
            if not os.path.isdir(type_dir):
                continue
            for fname in sorted(os.listdir(type_dir)):
                if fname.endswith(".png"):
                    episodes.append({
                        "map_path": os.path.join("maps_eval", env_type, fname),
                        "env_type": env_type
                    })

    planner = SimpleGreedyPlanner()
    per_episode = []
    per_type = {}

    for ep in episodes:
        map_path = os.path.join(data_path, ep["map_path"])
        env_type = ep.get("env_type", "unknown")
        env = ExplorationEnv(map_path=map_path)
        metrics = run_episode(env, planner)

        success = 1 if metrics.get("success", False) else 0
        distance = float(metrics.get("travel_distance", 0.0))
        explored = float(metrics.get("explored_rate", 0.0))

        per_episode.append({
            "map_path": ep["map_path"],
            "env_type": env_type,
            "success": success,
            "travel_distance": distance,
            "explored_rate": explored
        })

        if env_type not in per_type:
            per_type[env_type] = {
                "successes": 0,
                "succ_distances": [],
                "explored_rates": [],
                "count": 0
            }
        per_type[env_type]["successes"] += success
        if success:
            per_type[env_type]["succ_distances"].append(distance)
        per_type[env_type]["explored_rates"].append(explored)
        per_type[env_type]["count"] += 1

    total_episodes = len(per_episode)
    explored_rate = sum(ep["explored_rate"] for ep in per_episode) / total_episodes if total_episodes else 0.0
    success_rate = sum(ep["success"] for ep in per_episode) / total_episodes if total_episodes else 0.0
    successful_distances = [ep["travel_distance"] for ep in per_episode if ep["success"] == 1]
    travel_distance = sum(successful_distances) / len(successful_distances) if successful_distances else 0.0

    per_type_out = {}
    for env_type, data in per_type.items():
        cnt = data["count"]
        per_type_out[env_type] = {
            "explored_rate": sum(data["explored_rates"]) / cnt,
            "travel_distance": (sum(data["succ_distances"]) / len(data["succ_distances"])) if data["succ_distances"] else 0.0,
            "success_rate": data["successes"] / cnt
        }

    output = {
        "explored_rate": explored_rate,
        "travel_distance": travel_distance,
        "success_rate": success_rate,
        "per_episode": per_episode,
        "per_type": per_type_out,
        "total_episodes": total_episodes
    }

    with open(args.output, "w") as f:
        json.dump(output, f, indent=2)

    print(f"Eval complete: {total_episodes} episodes, success_rate={success_rate:.4f}, travel_distance={travel_distance:.1f}, explored_rate={explored_rate:.4f}")


if __name__ == "__main__":
    main()
